71	// ---------------------------------------------------------------------------
72	// A minimal prover whose `autoprove` parks on the gate (the "slow op"); every
73	// other callback is fast and gate-free.
74	// ---------------------------------------------------------------------------
75	
76	#[derive(Clone)]
77	struct Thy {
78	    lemmas: Vec<String>,
79	}
80	
81	struct GatedProver {
82	    gate: Arc<Gate>,
83	}
84	
85	fn base() -> Thy {
86	    Thy { lemmas: vec!["L".into()] }
87	}
88	
89	impl ProverOps for GatedProver {
90	    type Theory = Thy;
91	
92	    fn meta(&self, _thy: &Thy) -> Meta {
93	        Meta { name: "T".into(), version: "1.13.0".into(), filename: "T.spthy".into(), origin: Origin::Local }
94	    }
95	    fn root_meta(&self, _thy: &Thy) -> RootMeta {
96	        RootMeta { time: "00:00:00".into(), origin: "T.spthy".into(), modified: false }
97	    }
98	    fn source_text(&self, _thy: &Thy) -> String {
99	        "theory T begin\nend".into()
100	    }
101	    fn west_pane(&self, _thy: &Thy, index: u64) -> String {
102	        format!("WEST@{index}")
103	    }
104	    fn main_content(&self, _thy: &Thy, index: u64, _req: &MainReq) -> Content {
105	        Content { html: format!("<p>help@{index}</p>"), title: "T".into() }
106	    }
107	    fn lemma_source(&self, _thy: &Thy, name: &str) -> Option<String> {
108	        Some(format!("lemma {name}: exists-trace \"x\""))
109	    }
110	    fn graph_dot(&self, _thy: &Thy, _tail: &[String]) -> String {
111	        web_clean::intdot::EMPTY_GRAPH_DOT.to_string()
112	    }
113	    fn nav_target(&self, _thy: &Thy, index: u64, _dir: NavDir, _mode: &str, lemma: &str) -> String {
114	        format!("/thy/trace/{index}/main/proof/{lemma}")
115	    }
116	    fn append_message(&self, _thy: &Thy) -> String {
117	        "Appended".into()
118	    }
119	    fn static_file(&self, _path: &[String]) -> Option<Vec<u8>> {
120	        None
121	    }
122	    fn load_theory(&self, source: &str) -> Option<Thy> {
123	        source.contains("theory").then(|| Thy { lemmas: vec![] })
124	    }
125	    fn reload(&self, thy: &Thy) -> Thy {
126	        thy.clone()
127	    }
128	    /// The SLOW op: park on the gate (after the caller has already taken the
129	    /// snapshot and released the state lock), then produce the new version.
130	    fn autoprove(&self, thy: &Thy, _spec: &Autoprove) -> (Thy, Vec<String>) {
131	        self.gate.enter_and_park();
132	        (thy.clone(), vec!["_".into()])
133	    }
134	    /// The FAST op: no gate, returns immediately.
135	    fn apply_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
136	        (n != 0).then(|| (thy.clone(), vec!["_".into()]))
137	    }
138	    fn edit_lemma(&self, thy: &Thy, _n: &str, _t: &str) -> Option<Thy> {
139	        Some(thy.clone())
140	    }
141	    fn add_lemma(&self, thy: &Thy, _p: &str, _t: &str) -> Option<Thy> {
142	        Some(thy.clone())
143	    }
144	    fn delete_lemma(&self, thy: &Thy, name: &str) -> Option<Thy> {
145	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
146	    }
147	    fn lemma_present(&self, thy: &Thy, lemma: &str) -> bool {
148	        thy.lemmas.iter().any(|l| l == lemma)
149	    }
150	    fn del_lemma_path(&self, thy: &Thy, name: &str) -> Option<Thy> {
151	        thy.lemmas.iter().any(|l| l == name).then(|| thy.clone())
152	    }
153	    fn del_proof_step(&self, thy: &Thy, lemma: &str, _p: &[String], _d: bool) -> Option<Thy> {
154	        thy.lemmas.iter().any(|l| l == lemma).then(|| thy.clone())
155	    }
156	    fn apply_diff_method(&self, thy: &Thy, _l: &str, n: usize, _p: &[String]) -> Option<(Thy, Vec<String>)> {
157	        (n != 0).then(|| (thy.clone(), vec!["R".into()]))
158	    }
159	    fn autoprove_diff(&self, thy: &Thy, _s: &AutoproveDiff) -> (Thy, Vec<String>) {
160	        (thy.clone(), vec!["R".into()])
161	    }
162	    fn autoprove_all(&self, thy: &Thy, _s: &AutoproveAll) -> Thy {
163	        thy.clone()
164	    }
165	}
